   558→    public static int incrementSequence(int sequence, int increment) {
   559→        if (sequence > Integer.MAX_VALUE - increment)
   560→            return increment - (Integer.MAX_VALUE - sequence) - 1;
   561→        return sequence + increment;
   562→    }
