   213→        return filterResult;
   214→    }
   215→
   216→    private static BatchFilterResult filterBatch(RecordBatch batch,
   217→                                                 BufferSupplier decompressionBufferSupplier,
   218→                                                 FilterResult filterResult,
   219→                                                 RecordFilter filter) {
   220→        try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
   221→            long maxOffset = -1;
   222→            boolean containsTombstones = false;
   223→            // Convert records with old record versions
   224→            boolean writeOriginalBatch = batch.magic() >= RecordBatch.CURRENT_MAGIC_VALUE;
   225→            List<Record> retainedRecords = new ArrayList<>();
   226→            while (iterator.hasNext()) {
   227→                Record record = iterator.next();
   228→                filterResult.messagesRead += 1;
   229→
   230→                if (filter.shouldRetainRecord(batch, record)) {
   231→                    if (record.offset() > maxOffset)
   232→                        maxOffset = record.offset();
   233→
   234→                    retainedRecords.add(record);
   235→
   236→                    if (!record.hasValue()) {
   237→                        containsTombstones = true;
   238→                    }
   239→                } else {
   240→                    writeOriginalBatch = false;
   241→                }
   242→            }
   243→            return new BatchFilterResult(retainedRecords, writeOriginalBatch, containsTombstones, maxOffset);
   244→        }
   245→    }
   246→
   247→    private static class BatchFilterResult {
   248→        private final List<Record> retainedRecords;
   249→        private final boolean writeOriginalBatch;
   250→        private final boolean containsTombstones;
   251→        private final long maxOffset;
   252→        private BatchFilterResult(List<Record> retainedRecords,
   253→                                  final boolean writeOriginalBatch,
   254→                                  final boolean containsTombstones,
   255→                                  final long maxOffset) {
   256→            this.retainedRecords = retainedRecords;
   257→            this.writeOriginalBatch = writeOriginalBatch;
   258→            this.containsTombstones = containsTombstones;
   259→            this.maxOffset = maxOffset;
   260→        }
   261→    }
   262→
   263→    private static MemoryRecordsBuilder buildRetainedRecordsInto(RecordBatch originalBatch,
   264→                                                                 List<Record> retainedRecords,
   265→                                                                 ByteBufferOutputStream bufferOutputStream,
   266→                                                                 final long deleteHorizonMs) {
   267→        Compression compression = Compression.of(originalBatch.compressionType()).build();
   268→        // V0 has no timestamp type or timestamp, so we set the timestamp to CREATE_TIME and timestamp to NO_TIMESTAMP.
   269→        // Note that this differs from produce up-conversion where the timestamp type topic config is used and the log append
   270→        // time is generated if the config is LOG_APPEND_TIME. The reason for the different behavior is that there is
   271→        // no appropriate log append time we can generate at compaction time.
   272→        TimestampType timestampType = originalBatch.timestampType() == TimestampType.NO_TIMESTAMP_TYPE ?
   273→                TimestampType.CREATE_TIME : originalBatch.timestampType();
   274→        long logAppendTime = timestampType == TimestampType.LOG_APPEND_TIME ?
   275→                originalBatch.maxTimestamp() : RecordBatch.NO_TIMESTAMP;
   276→        long baseOffset = originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2 ?
   277→                originalBatch.baseOffset() : retainedRecords.get(0).offset();
   278→
   279→        // Convert records with older record versions to the current one
   280→        MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferOutputStream, RecordBatch.CURRENT_MAGIC_VALUE,
   281→                compression, timestampType, baseOffset, logAppendTime, originalBatch.producerId(),
   282→                originalBatch.producerEpoch(), originalBatch.baseSequence(), originalBatch.isTransactional(),
   283→                originalBatch.isControlBatch(), originalBatch.partitionLeaderEpoch(), bufferOutputStream.limit(), deleteHorizonMs);
   284→
   285→        for (Record record : retainedRecords)
   286→            builder.append(record);
   287→
   288→        if (originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2)
   289→            // we must preserve the last offset from the initial batch in order to ensure that the
   290→            // last sequence number from the batch remains even after compaction. Otherwise, the producer
   291→            // could incorrectly see an out of sequence error.
   292→            builder.overrideLastOffset(originalBatch.lastOffset());
   293→
   294→        return builder;
   295→    }
