   663→    public static MemoryRecords withRecords(byte magic, long initialOffset, Compression compression,
   664→                                            TimestampType timestampType, long producerId, short producerEpoch,
   665→                                            int baseSequence, int partitionLeaderEpoch, boolean isTransactional,
