   669→        int sizeEstimate = AbstractRecords.estimateSizeInBytes(magic, compression.type(), Arrays.asList(records));
   670→        ByteBufferOutputStream bufferStream = new ByteBufferOutputStream(sizeEstimate);
   671→        long logAppendTime = RecordBatch.NO_TIMESTAMP;
   672→        if (timestampType == TimestampType.LOG_APPEND_TIME)
   673→            logAppendTime = System.currentTimeMillis();
   674→        try (final MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferStream, magic, compression, timestampType,
   675→                initialOffset, logAppendTime, producerId, producerEpoch, baseSequence, isTransactional, false,
   676→                partitionLeaderEpoch, sizeEstimate)) {
   677→            for (SimpleRecord record : records)
   678→                builder.append(record);
   679→            return builder.build();
   680→        }
