   121→    static final int MAX_TIMESTAMP_LENGTH = 8;
   122→    static final int PRODUCER_ID_OFFSET = MAX_TIMESTAMP_OFFSET + MAX_TIMESTAMP_LENGTH;
   123→    static final int PRODUCER_ID_LENGTH = 8;
